  var mouseTrailAnimation = ({ elements }) => {
    const RAD2DEG = 180 / Math.PI;
    let windowWidth = window.innerWidth;
    let windowHeight = window.innerHeight;
    let lastY = 0;
    let lastX = 0;
    let currentRotation = 0;
    let mouseTween = tween_exports.createSpring({
      data: { x: 0, y: 0 },
      stagger: { each: 3, from: "start" }
    });
    for (const item of elements) {
      mouseTween.subscribe(({ x, y }) => {
        item.style.translate = `${x}px ${y}px`;
      });
    }
    let mouseTweenRotate = tween_exports.createSpring({
      data: { rotation: 0 },
      stagger: { each: 8, from: "start" }
    });
    for (const item of elements) {
      if (!item) continue;
      mouseTweenRotate.subscribeCache(({ rotation }) => {
        item.style.rotate = `${rotation}deg`;
      });
    }
    const unsubScribeResize = modules_exports.useResize(() => {
      windowWidth = window.innerWidth;
      windowHeight = window.innerHeight;
    });
    const unsubscribeMouseMove = modules_exports.useMouseMove(({ client }) => {
      const { x, y } = client;
      const yDiff = y - lastY;
      const xDiff = x - lastX;
      const distance = Math.hypot(xDiff, yDiff);
      if (distance > 10) {
        lastY = y;
        lastX = x;
        const targetAngle = Math.atan2(yDiff, xDiff) * RAD2DEG + 180 + 90;
        let delta = targetAngle - currentRotation;
        while (delta > 180) delta -= 360;
        while (delta < -180) delta += 360;
        currentRotation += delta;
        mouseTweenRotate.goTo({ rotation: currentRotation });
      }
      mouseTween.goTo({ x: x - windowWidth / 2, y: y - windowHeight / 2 });
    });
    return {
      destroy: () => {
        mouseTween.destroy();
        mouseTween = null;
        mouseTweenRotate.destroy();
        mouseTweenRotate = null;
        unsubScribeResize();
        unsubscribeMouseMove();
        windowWidth = null;
        windowHeight = null;
        lastY = null;
        lastX = null;
        currentRotation = null;
      }
    };
  };

